const full = $json;
const body = full.body ?? full;
const rows = Array.isArray(body.data) ? body.data : [];

function asInt(value) {
  if (value === null || value === undefined || value === '') return null;
  const n = Number(value);
  return Number.isFinite(n) ? Math.trunc(n) : null;
}

function normalizeTemplate(t) {
  const recipients = Array.isArray(t.recipients) ? t.recipients.slice() : [];
  const signerRecipients = recipients
    .filter(r => String(r.role || '').toUpperCase() === 'SIGNER' || r.signingOrder)
    .sort((a, b) => (asInt(a.signingOrder) ?? 999) - (asInt(b.signingOrder) ?? 999));

  const memberRecipient = signerRecipients.find(r => asInt(r.signingOrder) === 1) || signerRecipients[0] || null;
  const facilitatorRecipient = signerRecipients.find(r => asInt(r.signingOrder) === 2) || signerRecipients[1] || null;

  return {
    id: asInt(t.id),
    templateId: asInt(t.id),
    envelopeId: t.envelopeId || '',
    title: t.title || '',
    type: t.type || '',
    visibility: t.visibility || '',
    externalId: t.externalId || null,
    createdAt: t.createdAt || null,
    updatedAt: t.updatedAt || null,
    recipientCount: recipients.length,
    memberRecipientId: asInt(memberRecipient?.id),
    facilitatorRecipientId: asInt(facilitatorRecipient?.id),
    recipients
  };
}

return [{
  json: {
    data: rows.map(normalizeTemplate).filter(t => t.envelopeId),
    pagination: body.pagination || {},
    source: 'documenso'
  }
}];
